#include <windows.h>
#include <stdio.h>

// API Hashing to defeat static import analysis
DWORD HashString(char* str) {
    DWORD hash = 0x35;
    while (*str) {
        hash = ((hash << 5) + hash) + *str++;
    }
    return hash;
}

LPVOID GetProcAddressByHash(HMODULE hModule, DWORD dwApiHash) {
    PIMAGE_DOS_HEADER pDosHeader = (PIMAGE_DOS_HEADER)hModule;
    PIMAGE_NT_HEADERS pNtHeaders = (PIMAGE_NT_HEADERS)((DWORD_PTR)hModule + pDosHeader->e_lfanew);
    PIMAGE_EXPORT_DIRECTORY pExportDir = (PIMAGE_EXPORT_DIRECTORY)((DWORD_PTR)hModule + 
        pNtHeaders->OptionalHeader.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT].VirtualAddress);

    DWORD* pAddressOfFunctions = (DWORD*)((DWORD_PTR)hModule + pExportDir->AddressOfFunctions);
    DWORD* pAddressOfNames = (DWORD*)((DWORD_PTR)hModule + pExportDir->AddressOfNames);
    WORD* pAddressOfNameOrdinals = (WORD*)((DWORD_PTR)hModule + pExportDir->AddressOfNameOrdinals);

    for (DWORD i = 0; i < pExportDir->NumberOfNames; i++) {
        char* pFunctionName = (char*)((DWORD_PTR)hModule + pAddressOfNames[i]);
        if (HashString(pFunctionName) == dwApiHash) {
            return (LPVOID)((DWORD_PTR)hModule + pAddressOfFunctions[pAddressOfNameOrdinals[i]]);
        }
    }
    return NULL;
}

