```python
import struct
import os

def xor_encrypt(data, key):
    encrypted = bytearray()
    key_len = len(key)
    for i in range(len(data)):
        encrypted.append(data[i] ^ key[i % key_len])
    return bytes(encrypted)

def pack_exe(stub_path, target_path, output_path):
    # 1. Read the target payload
    with open(target_path, 'rb') as f:
        payload = f.read()

    # 2. Encrypt the payload (Simple XOR with 4-byte key 0x12345678)
    key = struct.pack('<I', 0x12345678)
    encrypted_payload = xor_encrypt(payload, key)

    # 3. Read the stub
    with open(stub_path, 'rb') as f:
        stub = f.read()

    # 4. Combine: Stub + Encrypted Payload + Payload Size
    # Note: The stub expects to find the size at the very end
    payload_size = struct.pack('<I', len(encrypted_payload))

    with open(output_path, 'wb') as f:
        f.write(stub)
        f.write(encrypted_payload)
        f.write(payload_size)

    print(f"[+] Packed {target_path} into {output_path}")
    print(f"[+] Stub size: {len(stub)} bytes")
    print(f"[+] Payload size: {len(encrypted_payload)} bytes")

if __name__ == "__main__":
    # Usage: python packer.py stub.exe target.exe packed.exe
    import sys
    if len(sys.argv) != 4:
        print("Usage: packer.py <stub.exe> <target.exe> <output.exe>")
        sys.exit(1)

    pack_exe(sys.argv[1], sys.argv[2], sys.argv[3])
```

